def semantic_search(


    query,

    top_k=5
):

    # EMBED QUERY

    query_embedding = model.encode(
        query
    )


    results = []



    # COMPARE AGAINST CHUNKS


    for chunk in embedded_chunks:


        similarity = cosine_similarity(

            query_embedding,

            chunk["embedding"]
        )


        results.append({

            "similarity": similarity,

            "chunk": chunk
        })


    # SORT RESULTS

    results.sort(

        key=lambda x: x["similarity"],

        reverse=True
    )


    return results[:top_k]

